        window.moddedAddSerialToBackpack = async function moddedAddSerialToBackpack(options) {
            if (typeof window.syncLegitBuilderCtxToActiveMainTab === 'function') {
                window.syncLegitBuilderCtxToActiveMainTab();
            }
            window.legitBuilderSetCtx(1);
            const overwriteSource = options && options.overwriteSource === true;
            const overwriteTarget = getActiveInventoryEditTarget();
            if (overwriteSource) {
                if (!overwriteTarget) {
                    const msg = 'Open an item from Save Editor or Profile Editor first to overwrite its original slot.';
                    notifyLegitBackpackToast(msg, 'error', 5000);
                    if (typeof showError === 'function') {
                        showError(msg);
                    } else {
                        alert(msg);
                    }
                    return;
                }
                if (overwriteTarget.kind === 'bank') {
                    if (!isProfileLoadedForInventoryTarget()) {
                        if (typeof loadProfileFileFromItemEditor === 'function') {
                            loadProfileFileFromItemEditor();
                        }
                        return;
                    }
                } else if (!window.saveEditorState || !window.saveEditorState.isLoaded) {
                    if (typeof loadSaveFileFromItemEditor === 'function') {
                        loadSaveFileFromItemEditor();
                    }
                    return;
                }
            } else if (!window.saveEditorState || !window.saveEditorState.isLoaded) {
                if (typeof loadSaveFileFromItemEditor === 'function') {
                    loadSaveFileFromItemEditor();
                }
                return;
            }
            const serialInputEl =
                window.__lbCtx && window.__lbCtx.relaxedPicker ? lbGeneratedHumanEl() : lbSerialInputEl();
            let rawEarly = serialInputEl ? serialInputEl.value.trim() : '';
            if (!rawEarly) {
                const msg = 'Paste or build a serial in Generated Item Code first.';
                notifyLegitBackpackToast(msg, 'error', 5000);
                if (typeof showError === 'function') {
                    showError(msg);
                } else {
                    alert(msg);
                }
                return;
            }
            try {
                if (isBase85Format(rawEarly)) {
                    const normB85 = rawEarly.startsWith('@') ? rawEarly : '@' + rawEarly;
                    window.__legitBackpackContext = window.__legitBackpackContext || {};
                    window.__legitBackpackContext.lastBase85 = normB85;
                    window.__legitBackpackContext.pendingFromB85 = false;
                    await writeSerializedToInventoryTarget(normB85, { overwriteSource });
                    return;
                }
                let deser =
                    typeof mergeModdedSkinUiIntoHumanSerialText === 'function'
                        ? mergeModdedSkinUiIntoHumanSerialText(rawEarly)
                        : rawEarly;
                deser = String(deser || '').trim();
                if (
                    typeof normalizeDeserializedSerialInterPartSpacing === 'function' &&
                    deser
                ) {
                    const spaced = normalizeDeserializedSerialInterPartSpacing(deser);
                    if (spaced && spaced !== deser) {
                        deser = spaced;
                        if (serialInputEl) {
                            serialInputEl.value = deser;
                        }
                    }
                }
                window.__legitBackpackContext = window.__legitBackpackContext || {};
                window.__legitBackpackContext.lastDeserialized = deser;
                window.__legitBackpackContext.lastBase85 = null;
                window.__legitBackpackContext.pendingFromB85 = false;
                const b85El = lbEl('finalOutputBase85');
                let b85 = '';
                if (b85El) {
                    const t = String(b85El.value || '').trim();
                    if (t && t !== 'Serializing...' && t.indexOf('Error:') !== 0) {
                        b85 = t.startsWith('@') ? t : '@' + t;
                    }
                }
                if (!b85) {
                    b85 = await resolveSerialB85ForBackpack(deser, null);
                }
                await yieldToPaintLegit();
                await writeSerializedToInventoryTarget(b85, { overwriteSource });
            } catch (err) {
                console.error(err);
                const m = err && err.message ? err.message : String(err);
                notifyLegitBackpackToast(m, 'error', 5000);
                if (typeof showError === 'function') {
                    showError(m);
                } else {
                    alert(m);
                }
            }
        };

